// // This module implements a 5-to-32 decoder with an enable signal. When the enable signal is low, the decoder should output a one-hot encoded signal based on the 5-bit input. When the enable signal is high, all output bits should be 0.
module decoder5to32(
	input 	clk,
	input 	rst,
	input 	enable,
	input 	[4:0] input_data,
	output reg [31:0] output_data
);

always @(posedge clk or posedge rst)
begin
	if (rst)
		output_data <= 32'b0;
	else if (enable)
		output_data <= 1 << input_data;
	else
		output_data <= 32'b0;
end

endmodule
